);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
$xmin = -7;
$xmax = 7;
$ymin = -7;
$ymax = 7;
Context("Fraction");
do {
  do {
    ($n,$d) = random_coprime([2..9],[2..9]);
    $m = Fraction($n/$d);
    ($h,$k) = random_subset(2,-5..-1,1..5);
    $f = Formula("$m(x - $h) + $k")->reduce;
    $b = $f->eval(x => 0);
  } until ($b != 0);
  $xtop = ($ymax - $k)/$m + $h;
  $xbot = ($ymin - $k)/$m + $h;
  ($start, $stop) = (num_sort($xmin,$xmax,$xtop,$xbot))[1,2];
  @x = ();
  @y = ();
  $a = ($start < 0) ? int(Real($start)) : int(Real($start)) + 1;
  $b = ($stop < 0) ? int(Real($stop)) - 1 : int(Real($stop));
  for ($a .. $b) {
    if ($f->eval(x => $_) == int($f->eval(x => $_))) {
      push @x, $_;
      push @y, $f->eval(x => $_);
    }
  }
} until (scalar @x >= 2);
@fs = map {Formula("$m*(x - $x[$_]) + $y[$_]")->reduce} (0..$#x);

package my::OneOf;
our @ISA = ('parser::OneOf');
sub cmp_compare {
  my ($self,$other,$ans) = @_;
  foreach $answer (@{$self->{data}}) {
    if ($answer->typeMatch($other)) {
      my $result = $answer->cmp->evaluate($other);
      if ($result->{score}) {
        $ans->score($result->{score});
        $ans->{ans_message} = $result->{ans_message};
        return $ans->{score};
      }
      if ($result->{ans_message}) {
        $ans->{ans_message} = $result->{ans_message}
          if !$ans->{ans_message} || length($ans->{ans_message}) > length($result->{ans_message});
      }
    }
  }
  return 0;
}
package main;
sub OneOfForm {my::OneOf->new(@_)}

Context("Form")->variables->add(y=>'Real');
parser::Assignment->Allow;
Context()->noreduce('(-x)+y','(-x)-y');
Context()->flags->set(reduceConstants => 0);
$eq = OneOfForm(map {Formula("y=$_")} @fs);

$image_1 = createLaTeXImage();
$image_1->addToPreamble(latexImagePreamble());
$image_1->BEGIN_LATEX_IMAGE
\begin{tikzpicture}
  \begin{axis}[
      width=0.33\orccaprintwidth,
    ]
    \addplot[firstcurve, domain=$start:$stop]{$f};
  \end{axis}
\end{tikzpicture}

END_LATEX_IMAGE

############################################################
# Body
############################################################

BEGIN_PGML
Determine a point-slope form line equation for the given line.

>> [@image(insertGraph($image_1), width=>600)@]*  <<

[_]{$eq}{16}

END_PGML

############################################################
# Solution
############################################################

BEGIN_PGML_SOLUTION
The slope is [`[$m]`] and the point [`([$h],[$k])`] is on the graph of this line, so one point-slope form equation for this line is [`y=[$f]\text{.}`]

END_PGML_SOLUTION

